class UserRegistrationSystem:
    """Handles user registration, authentication, and profile management."""

    def __init__(self):
        self._users: dict[str, UserProfile] = {}
        self._email_index: dict[str, str] = {}
        self._username_index: dict[str, str] = {}
        self._sessions: dict[str, str] = {}

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def _generate_session_token(self) -> str:
        return str(uuid.uuid4())

    def register_user(self, username: str, email: str, password: str,
                      role: UserRole = UserRole.LEARNER) -> dict:
        if email in self._email_index:
            return {"success": False, "error": "Email already registered"}
        if username in self._username_index:
            return {"success": False, "error": "Username already taken"}
        if len(password) < 8:
            return {"success": False, "error": "Password must be at least 8 characters"}

        user_id = str(uuid.uuid4())
        user = UserProfile(
            user_id=user_id,
            username=username,
            email=email,
            password_hash=self._hash_password(password),
            role=role,
            created_at=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )
        self._users[user_id] = user
        self._email_index[email] = user_id
        self._username_index[username] = user_id
        return {"success": True, "user_id": user_id}

    def authenticate(self, email: str, password: str) -> dict:
        user_id = self._email_index.get(email)
        if not user_id:
            return {"success": False, "error": "Invalid credentials"}
        user = self._users[user_id]
        if user.password_hash != self._hash_password(password):
            return {"success": False, "error": "Invalid credentials"}
        if not user.is_active:
            return {"success": False, "error": "Account is deactivated"}
        token = self._generate_session_token()
        self._sessions[token] = user_id
        return {"success": True, "token": token, "user_id": user_id}

    def logout(self, token: str) -> dict:
        if token in self._sessions:
            del self._sessions[token]
            return {"success": True}
        return {"success": False, "error": "Invalid session"}

    def get_user_by_token(self, token: str) -> Optional[UserProfile]:
        user_id = self._sessions.get(token)
        if user_id:
            return self._users.get(user_id)
        return None

    def get_user(self, user_id: str) -> Optional[UserProfile]:
        return self._users.get(user_id)

    def update_profile_picture(self, user_id: str, picture_path: str) -> dict:
        user = self._users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}
        allowed_extensions = (".jpg", ".jpeg", ".png", ".gif", ".webp")
        if not picture_path.lower().endswith(allowed_extensions):
            return {"success": False, "error": "Invalid image format"}
        user.profile_picture = picture_path
        return {"success": True, "profile_picture": picture_path}

    def update_cultural_background(self, user_id: str,
                                   background: CulturalBackground) -> dict:
        user = self._users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}
        user.cultural_background = background
        return {"success": True}

    def search_users(self, language: Optional[str] = None,
                     country: Optional[str] = None,
                     interest: Optional[str] = None) -> list:
        results = []
        for user in self._users.values():
            if not user.is_active or not user.cultural_background:
                continue
            bg = user.cultural_background
            if language and language.lower() not in [l.lower() for l in bg.languages]:
                continue
            if country and country.lower() != bg.country.lower():
                continue
            if interest and interest.lower() not in [i.lower() for i in bg.interests]:
                continue
            results.append(user.to_dict())
        return results

    def deactivate_user(self, user_id: str) -> dict:
        user = self._users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}
        user.is_active = False
        tokens_to_remove = [t for t, uid in self._sessions.items() if uid == user_id]
        for t in tokens_to_remove:
            del self._sessions[t]
        return {"success": True}

    def get_all_users(self) -> list:
        return [u.to_dict() for u in self._users.values() if u.is_active]


