class VirtualTourModule:
    """Manages virtual tours of cultural landmarks and historical sites."""

    def __init__(self, user_system: UserRegistrationSystem):
        self._user_system = user_system
        self._tours: dict[str, VirtualTour] = {}
        self._user_visits: dict[str, list] = {}
        self._bookmarks: dict[str, list] = {}

    def create_tour(self, creator_id: str, title: str, description: str,
                    country: str, region: str, model_url: str,
                    thumbnail_url: str, tags: Optional[list] = None) -> dict:
        creator = self._user_system.get_user(creator_id)
        if not creator:
            return {"success": False, "error": "User not found"}
        if creator.role not in (UserRole.EXPERT, UserRole.ADMIN):
            return {"success": False, "error": "Only experts and admins can create tours"}

        tour_id = str(uuid.uuid4())
        tour = VirtualTour(
            tour_id=tour_id,
            title=title,
            description=description,
            country=country,
            region=region,
            model_url=model_url,
            thumbnail_url=thumbnail_url,
            created_by=creator_id,
            created_at=datetime.datetime.now(datetime.timezone.utc).isoformat(),
            tags=tags or [],
        )
        self._tours[tour_id] = tour
        return {"success": True, "tour_id": tour_id}

    def add_hotspot(self, tour_id: str, name: str,
                    hotspot_type: HotspotType, position: dict,
                    content: str, audio_url: Optional[str] = None) -> dict:
        tour = self._tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}
        if not all(k in position for k in ("x", "y", "z")):
            return {"success": False, "error": "Position must include x, y, z"}

        hotspot_id = str(uuid.uuid4())
        hotspot = Hotspot(
            hotspot_id=hotspot_id,
            name=name,
            hotspot_type=hotspot_type,
            position=position,
            content=content,
            audio_url=audio_url,
        )
        tour.hotspots.append(hotspot)
        return {"success": True, "hotspot_id": hotspot_id}

    def add_audio_guide(self, tour_id: str, title: str, language: str,
                        audio_url: str, transcript: str,
                        duration_seconds: int) -> dict:
        tour = self._tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        guide_id = str(uuid.uuid4())
        guide = AudioGuide(
            guide_id=guide_id,
            title=title,
            language=language,
            audio_url=audio_url,
            transcript=transcript,
            duration_seconds=duration_seconds,
        )
        tour.audio_guides.append(guide)
        return {"success": True, "guide_id": guide_id}

    def visit_tour(self, user_id: str, tour_id: str) -> dict:
        user = self._user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}
        tour = self._tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        tour.visitor_count += 1
        visit_record = {
            "tour_id": tour_id,
            "visited_at": datetime.datetime.now(datetime.timezone.utc).isoformat(),
        }
        self._user_visits.setdefault(user_id, []).append(visit_record)
        return {"success": True, "tour": tour.to_dict()}

    def interact_with_hotspot(self, tour_id: str, hotspot_id: str) -> dict:
        tour = self._tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}
        hotspot = next((h for h in tour.hotspots if h.hotspot_id == hotspot_id), None)
        if not hotspot:
            return {"success": False, "error": "Hotspot not found"}
        if not hotspot.is_interactive:
            return {"success": False, "error": "Hotspot is not interactive"}
        return {"success": True, "hotspot": hotspot.to_dict()}

    def get_tour(self, tour_id: str) -> Optional[dict]:
        tour = self._tours.get(tour_id)
        return tour.to_dict() if tour else None

    def search_tours(self, country: Optional[str] = None,
                     tag: Optional[str] = None,
                     keyword: Optional[str] = None) -> list:
        results = []
        for tour in self._tours.values():
            if country and tour.country.lower() != country.lower():
                continue
            if tag and tag.lower() not in [t.lower() for t in tour.tags]:
                continue
            if keyword:
                kw = keyword.lower()
                if kw not in tour.title.lower() and kw not in tour.description.lower():
                    continue
            results.append(tour.to_dict())
        return results

    def get_popular_tours(self, limit: int = 10) -> list:
        sorted_tours = sorted(self._tours.values(),
                              key=lambda t: t.visitor_count, reverse=True)
        return [t.to_dict() for t in sorted_tours[:limit]]

    def bookmark_tour(self, user_id: str, tour_id: str) -> dict:
        if tour_id not in self._tours:
            return {"success": False, "error": "Tour not found"}
        bookmarks = self._bookmarks.setdefault(user_id, [])
        if tour_id in bookmarks:
            return {"success": False, "error": "Already bookmarked"}
        bookmarks.append(tour_id)
        return {"success": True}

    def get_user_bookmarks(self, user_id: str) -> list:
        tour_ids = self._bookmarks.get(user_id, [])
        return [self._tours[tid].to_dict() for tid in tour_ids if tid in self._tours]


