class TranslationTool:
    """Simulated translation engine for language exchange assistance."""

    SUPPORTED_LANGUAGES = [
        "english", "spanish", "french", "german", "italian",
        "portuguese", "japanese", "chinese", "korean", "arabic",
        "hindi", "russian", "dutch", "swedish", "turkish",
    ]

    def translate(self, text: str, source_lang: str,
                  target_lang: str) -> TranslationResult:
        source = source_lang.lower()
        target = target_lang.lower()
        if source not in self.SUPPORTED_LANGUAGES:
            raise ValueError(f"Unsupported source language: {source_lang}")
        if target not in self.SUPPORTED_LANGUAGES:
            raise ValueError(f"Unsupported target language: {target_lang}")

        # Simulated translation with marker
        translated = f"[{target}] {text}"
        confidence = round(random.uniform(0.85, 0.99), 2)
        return TranslationResult(
            source_text=text,
            source_language=source,
            target_language=target,
            translated_text=translated,
            confidence=confidence,
            timestamp=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )

    def detect_language(self, text: str) -> dict:
        return {
            "detected_language": "english",
            "confidence": 0.95,
        }

    def get_supported_languages(self) -> list:
        return self.SUPPORTED_LANGUAGES


class LanguageLearningModule:
    """Pairs users for real-time language exchanges with translation support."""

    def __init__(self, user_system: UserRegistrationSystem,
                 tour_module: VirtualTourModule):
        self._user_system = user_system
        self._tour_module = tour_module
        self._translation_tool = TranslationTool()
        self._sessions: dict[str, LanguageSession] = {}
        self._waiting_pool: dict[str, list] = {}  # language -> [user_ids]
        self._user_sessions: dict[str, list] = {}

    def request_pairing(self, user_id: str, practice_language: str,
                        native_language: str) -> dict:
        user = self._user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        practice = practice_language.lower()
        native = native_language.lower()
        if practice not in TranslationTool.SUPPORTED_LANGUAGES:
            return {"success": False, "error": f"Unsupported language: {practice_language}"}

        # Look for complementary partner
        partner_key = f"{native}_{practice}"
        if partner_key in self._waiting_pool and self._waiting_pool[partner_key]:
            partner_id = self._waiting_pool[partner_key].pop(0)
            if not self._waiting_pool[partner_key]:
                del self._waiting_pool[partner_key]
            return self._create_session(user_id, partner_id, practice, native)

        # Add to waiting pool
        request_key = f"{practice}_{native}"
        self._waiting_pool.setdefault(request_key, []).append(user_id)
        return {
            "success": True,
            "status": PairingStatus.WAITING.value,
            "message": "Waiting for a partner...",
        }

    def _create_session(self, user1_id: str, user2_id: str,
                        lang1: str, lang2: str) -> dict:
        session_id = str(uuid.uuid4())
        session = LanguageSession(
            session_id=session_id,
            participants=[user1_id, user2_id],
            source_language=lang1,
            target_language=lang2,
            status=PairingStatus.PAIRED,
            started_at=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )
        self._sessions[session_id] = session
        self._user_sessions.setdefault(user1_id, []).append(session_id)
        self._user_sessions.setdefault(user2_id, []).append(session_id)
        return {
            "success": True,
            "status": PairingStatus.PAIRED.value,
            "session_id": session_id,
            "partner_id": user2_id,
        }

    def start_session(self, session_id: str) -> dict:
        session = self._sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if session.status != PairingStatus.PAIRED:
            return {"success": False, "error": "Session is not in paired state"}
        session.status = PairingStatus.IN_SESSION
        return {"success": True, "session": session.to_dict()}

    def send_message(self, session_id: str, sender_id: str, text: str,
                     auto_translate: bool = True) -> dict:
        session = self._sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        if sender_id not in session.participants:
            return {"success": False, "error": "User not in this session"}
        if session.status != PairingStatus.IN_SESSION:
            return {"success": False, "error": "Session is not active"}

        message = {
            "sender_id": sender_id,
            "text": text,
            "timestamp": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "translation": None,
        }

        if auto_translate:
            try:
                result = self._translation_tool.translate(
                    text, session.source_language, session.target_language
                )
                message["translation"] = {
                    "translated_text": result.translated_text,
                    "confidence": result.confidence,
                }
                session.translations.append(result)
            except ValueError:
                pass

        session.messages.append(message)
        return {"success": True, "message": message}

    def translate_text(self, text: str, source_lang: str,
                       target_lang: str) -> dict:
        try:
            result = self._translation_tool.translate(text, source_lang, target_lang)
            return {
                "success": True,
                "translated_text": result.translated_text,
                "confidence": result.confidence,
            }
        except ValueError as e:
            return {"success": False, "error": str(e)}

    def end_session(self, session_id: str) -> dict:
        session = self._sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}
        session.status = PairingStatus.COMPLETED
        session.ended_at = datetime.datetime.now(datetime.timezone.utc).isoformat()
        if session.started_at:
            start = datetime.datetime.fromisoformat(session.started_at)
            end = datetime.datetime.fromisoformat(session.ended_at)
            session.duration_minutes = int((end - start).total_seconds() / 60)
        return {"success": True, "session": session.to_dict()}

    def get_session(self, session_id: str) -> Optional[dict]:
        session = self._sessions.get(session_id)
        return session.to_dict() if session else None

    def get_user_sessions(self, user_id: str) -> list:
        session_ids = self._user_sessions.get(user_id, [])
        return [self._sessions[sid].to_dict() for sid in session_ids
                if sid in self._sessions]

    def get_supported_languages(self) -> list:
        return self._translation_tool.get_supported_languages()

    def cancel_pairing(self, user_id: str) -> dict:
        for key, pool in list(self._waiting_pool.items()):
            if user_id in pool:
                pool.remove(user_id)
                if not pool:
                    del self._waiting_pool[key]
                return {"success": True}
        return {"success": False, "error": "No pending pairing request found"}


