class CulturalWorkshopModule:
    """Hosts live and pre-recorded cultural sessions led by experts."""

    def __init__(self, user_system: UserRegistrationSystem,
                 language_module: LanguageLearningModule):
        self._user_system = user_system
        self._language_module = language_module
        self._workshops: dict[str, Workshop] = {}
        self._user_workshops: dict[str, list] = {}
        self._categories = [
            "cooking", "music", "dance", "art", "history",
            "traditions", "festivals", "crafts", "storytelling", "meditation",
        ]

    def create_workshop(self, host_id: str, title: str, description: str,
                        workshop_type: WorkshopType, category: str,
                        scheduled_at: str, duration_minutes: int = 60,
                        max_participants: int = 50,
                        tags: Optional[list] = None) -> dict:
        host = self._user_system.get_user(host_id)
        if not host:
            return {"success": False, "error": "Host user not found"}
        if host.role not in (UserRole.EXPERT, UserRole.ADMIN):
            return {"success": False, "error": "Only experts can host workshops"}
        if category.lower() not in self._categories:
            return {"success": False, "error": f"Invalid category. Choose from: {self._categories}"}

        workshop_id = str(uuid.uuid4())
        workshop = Workshop(
            workshop_id=workshop_id,
            title=title,
            description=description,
            workshop_type=workshop_type,
            host_id=host_id,
            category=category.lower(),
            scheduled_at=scheduled_at,
            duration_minutes=duration_minutes,
            max_participants=max_participants,
            tags=tags or [],
            created_at=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )
        self._workshops[workshop_id] = workshop
        self._user_workshops.setdefault(host_id, []).append(workshop_id)
        return {"success": True, "workshop_id": workshop_id}

    def join_workshop(self, user_id: str, workshop_id: str) -> dict:
        user = self._user_system.get_user(user_id)
        if not user:
            return {"success": False, "error": "User not found"}
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.status == WorkshopStatus.CANCELLED:
            return {"success": False, "error": "Workshop has been cancelled"}
        if user_id in workshop.participants:
            return {"success": False, "error": "Already joined this workshop"}
        if len(workshop.participants) >= workshop.max_participants:
            return {"success": False, "error": "Workshop is full"}

        workshop.participants.append(user_id)
        self._user_workshops.setdefault(user_id, []).append(workshop_id)
        return {"success": True, "workshop": workshop.to_dict()}

    def leave_workshop(self, user_id: str, workshop_id: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if user_id not in workshop.participants:
            return {"success": False, "error": "Not a participant"}
        workshop.participants.remove(user_id)
        if workshop_id in self._user_workshops.get(user_id, []):
            self._user_workshops[user_id].remove(workshop_id)
        return {"success": True}

    def start_workshop(self, workshop_id: str, host_id: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can start the workshop"}
        if workshop.status != WorkshopStatus.SCHEDULED:
            return {"success": False, "error": "Workshop cannot be started"}
        workshop.status = WorkshopStatus.IN_PROGRESS
        return {"success": True, "workshop": workshop.to_dict()}

    def end_workshop(self, workshop_id: str, host_id: str,
                     recording_url: Optional[str] = None) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can end the workshop"}
        workshop.status = WorkshopStatus.COMPLETED
        if recording_url:
            workshop.recording_url = recording_url
        return {"success": True, "workshop": workshop.to_dict()}

    def ask_question(self, workshop_id: str, user_id: str, text: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to ask questions"}

        question_id = str(uuid.uuid4())
        question = WorkshopQuestion(
            question_id=question_id,
            user_id=user_id,
            text=text,
            timestamp=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )
        workshop.questions.append(question)
        return {"success": True, "question_id": question_id}

    def answer_question(self, workshop_id: str, question_id: str,
                        answerer_id: str, answer: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        question = next(
            (q for q in workshop.questions if q.question_id == question_id), None
        )
        if not question:
            return {"success": False, "error": "Question not found"}
        question.answer = answer
        question.answered_by = answerer_id
        return {"success": True, "question": question.to_dict()}

    def upvote_question(self, workshop_id: str, question_id: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        question = next(
            (q for q in workshop.questions if q.question_id == question_id), None
        )
        if not question:
            return {"success": False, "error": "Question not found"}
        question.upvotes += 1
        return {"success": True, "upvotes": question.upvotes}

    def post_discussion(self, workshop_id: str, user_id: str, text: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant"}

        message_id = str(uuid.uuid4())
        message = DiscussionMessage(
            message_id=message_id,
            user_id=user_id,
            text=text,
            timestamp=datetime.datetime.now(datetime.timezone.utc).isoformat(),
        )
        workshop.discussions.append(message)
        return {"success": True, "message_id": message_id}

    def add_material(self, workshop_id: str, host_id: str,
                     material_url: str, title: str) -> dict:
        workshop = self._workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}
        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can add materials"}
        workshop.materials.append({"url": material_url, "title": title})
        return {"success": True}

    def get_workshop(self, workshop_id: str) -> Optional[dict]:
        workshop = self._workshops.get(workshop_id)
        return workshop.to_dict() if workshop else None

    def search_workshops(self, category: Optional[str] = None,
                         workshop_type: Optional[WorkshopType] = None,
                         status: Optional[WorkshopStatus] = None,
                         keyword: Optional[str] = None) -> list:
        results = []
        for ws in self._workshops.values():
            if category and ws.category != category.lower():
                continue
            if workshop_type and ws.workshop_type != workshop_type:
                continue
            if status and ws.status != status:
                continue
            if keyword:
                kw = keyword.lower()
                if kw not in ws.title.lower() and kw not in ws.description.lower():
                    continue
            results.append(ws.to_dict())
        return results

    def get_categories(self) -> list:
        return self._categories

    def get_user_workshops(self, user_id: str) -> list:
        workshop_ids = self._user_workshops.get(user_id, [])
        return [self._workshops[wid].to_dict() for wid in workshop_ids
                if wid in self._workshops]


