class CulturalExchangeHub:
    """
    Central orchestrator connecting all modules of the platform.
    Modules are initialized in dependency order:
      1. User Registration System
      2. Virtual Tour Module (depends on 1)
      3. Language Learning Module (depends on 1, 2)
      4. Cultural Workshop Module (depends on 1, 3)
      5. Feedback & Rating System (depends on 1, 2, 3, 4)
    """

    def __init__(self):
        # Module 1: User Registration
        self.users = UserRegistrationSystem()
        # Module 2: Virtual Tours (requires users)
        self.tours = VirtualTourModule(self.users)
        # Module 3: Language Learning (requires users, tours)
        self.languages = LanguageLearningModule(self.users, self.tours)
        # Module 4: Cultural Workshops (requires users, languages)
        self.workshops = CulturalWorkshopModule(self.users, self.languages)
        # Module 5: Feedback & Ratings (requires all above)
        self.feedback = FeedbackAndRatingSystem(
            self.users, self.tours, self.languages, self.workshops
        )

    def get_platform_stats(self) -> dict:
        return {
            "total_users": len(self.users.get_all_users()),
            "total_tours": len(self.tours._tours),
            "total_language_sessions": len(self.languages._sessions),
            "total_workshops": len(self.workshops._workshops),
            "total_reviews": len(self.feedback._reviews),
        }

    def get_recommendations_for_user(self, user_id: str) -> dict:
        """Generate personalized recommendations based on user's cultural background."""
        user = self.users.get_user(user_id)
        if not user or not user.cultural_background:
            return {"tours": [], "workshops": [], "language_partners": []}

        bg = user.cultural_background

        # Recommend tours from countries in user interests
        recommended_tours = []
        for interest in bg.interests:
            tours = self.tours.search_tours(keyword=interest)
            recommended_tours.extend(tours[:3])

        # Recommend workshops matching interests
        recommended_workshops = []
        for interest in bg.interests:
            workshops = self.workshops.search_workshops(keyword=interest)
            recommended_workshops.extend(workshops[:3])

        # Recommend language partners
        language_partners = []
        for lang in bg.languages:
            partners = self.users.search_users(language=lang)
            partners = [p for p in partners if p["user_id"] != user_id]
            language_partners.extend(partners[:3])

        return {
            "tours": recommended_tours[:5],
            "workshops": recommended_workshops[:5],
            "language_partners": language_partners[:5],
        }


